// ═══════════════════════════════════════
// VALIDACIÓN Y ANONIMIZACIÓN DE INPUT
// ═══════════════════════════════════════

const input = $input.first().json.body || $input.first().json;

const required = ['patientId', 'symptoms'];
const missing = required.filter(f => !input[f]);

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error: `Campos faltantes: ${missing.join(', ')}`,
      statusCode: 400
    }
  }];
}

// Hash del patientId para no loggear data identificable
const hashId = (id) => {
  let h = 0;
  for (let i = 0; i < String(id).length; i++) {
    h = ((h << 5) - h) + String(id).charCodeAt(i);
  }
  return 'hash_' + Math.abs(h).toString(36);
};

const vitals = input.vitals || {};
const bpSystolic = vitals.bp ? parseInt(String(vitals.bp).split('/')[0]) : null;

// Flag de signos vitales críticos
const hasCriticalVitals = (
  (vitals.spo2 != null && vitals.spo2 < 92) ||
  (vitals.hr != null && (vitals.hr > 110 || vitals.hr < 50)) ||
  (bpSystolic != null && bpSystolic > 170) ||
  (vitals.temp != null && vitals.temp >= 39)
);

return [{
  json: {
    valid: true,
    patientHash: hashId(input.patientId),
    age: input.age || null,
    symptoms: String(input.symptoms).trim(),
    vitals,
    hasCriticalVitals,
    timestamp: new Date().toISOString()
  }
}];

// ═══════════════════════════════════════
// BÚSQUEDA SEMÁNTICA CON EMBEDDINGS (SIMULADA)
// ═══════════════════════════════════════

const input = $input.first().json;

const clinicalDocs = [
  {
    id: 'doc-001',
    title: 'Protocolo Síndrome Coronario Agudo',
    content: 'El dolor toracico opresivo irradiado a brazo izquierdo con disnea sugiere infarto agudo de miocardio. Actuar en ventana dorada menor a 90 minutos. Solicitar ECG, troponinas, activar hemodinamia.',
    specialty: 'cardiologia',
    urgency: 'critica'
  },
  {
    id: 'doc-002',
    title: 'Manejo de Crisis Hipertensiva',
    content: 'Presion arterial mayor a 180/120 con sintomas como cefalea intensa, vision borrosa o dolor toracico indica emergencia hipertensiva. Descenso controlado de PA 20 por ciento primera hora.',
    specialty: 'cardiologia',
    urgency: 'alta'
  },
  {
    id: 'doc-003',
    title: 'Evaluación de Disnea Aguda',
    content: 'Dificultad respiratoria con saturacion menor a 92 por ciento requiere oxigenoterapia inmediata. Diagnosticos diferenciales TEP, neumonia, insuficiencia cardiaca, broncoespasmo.',
    specialty: 'neumologia',
    urgency: 'alta'
  },
  {
    id: 'doc-004',
    title: 'Protocolo Sepsis Temprana',
    content: 'Fiebre con taquicardia e hipotension en contexto de infeccion. Aplicar qSOFA. Bundle de sepsis cultivos, lactato, antibioticos en primera hora, fluidos cristaloides.',
    specialty: 'infectologia',
    urgency: 'critica'
  },
  {
    id: 'doc-005',
    title: 'Cefalea de Alarma - Red Flags',
    content: 'Cefalea subita intensa thunderclap, focalidad neurologica, fiebre, trauma craneal reciente o mayor a 50 años. Descartar HSA, meningitis, tumor. TC de cerebro urgente.',
    specialty: 'neurologia',
    urgency: 'alta'
  },
  {
    id: 'doc-006',
    title: 'Consulta General - Baja Complejidad',
    content: 'Sintomas leves sin signos de alarma. Evaluacion ambulatoria estandar, seguimiento por medico de cabecera. Educar sobre signos de empeoramiento.',
    specialty: 'clinica',
    urgency: 'baja'
  }
];

function embed(text) {
  const vec = new Array(128).fill(0);
  const words = String(text).toLowerCase()
    .replace(/[^a-záéíóúñ ]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2);

  words.forEach(w => {
    for (let i = 0; i < w.length; i++) {
      vec[(w.charCodeAt(i) * 31 + i) % 128] += 1;
    }
  });

  const mag = Math.sqrt(vec.reduce((s, v) => s + v * v, 0));
  return mag > 0 ? vec.map(v => v / mag) : vec;
}

function cosineSim(a, b) {
  return a.reduce((s, v, i) => s + v * b[i], 0);
}

const queryVec = embed(input.symptoms);

const ranked = clinicalDocs
  .map(doc => ({
    ...doc,
    similarity: +cosineSim(queryVec, embed(doc.content + ' ' + doc.title)).toFixed(4)
  }))
  .sort((a, b) => b.similarity - a.similarity)
  .slice(0, 3);

return [{
  json: {
    ...input,
    relevantDocs: ranked,
    topDocContext: ranked.map(d => `[${d.title}]: ${d.content}`).join('\n\n')
  }
}];

