// ═══════════════════════════════════════
// PARSER ROBUSTO DE RESPUESTA IA
// ═══════════════════════════════════════
// Maneja: JSON directo, markdown code fences, texto extra alrededor

const aiData = $input.first().json;
const previousData = $('🔍 Búsqueda Semántica').first().json;

function extractJson(text) {
  if (text == null) return null;
  if (typeof text === 'object') return text;
  if (typeof text !== 'string') return null;

  // 1. Intento directo
  try { return JSON.parse(text); } catch (e) {}

  // 2. Limpiar markdown code fences
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim();
  try { return JSON.parse(cleaned); } catch (e) {}

  // 3. Extraer primer bloque { ... } con regex
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (e) {}
  }

  return null;
}

const content = aiData?.choices?.[0]?.message?.content;
const parsed = extractJson(content);

if (!parsed) {
  // Parseo falló — usar datos de búsqueda semántica como fallback
  return [{
    json: {
      ...previousData,
      aiAnalysis: {
        analysis: 'No se pudo parsear respuesta IA — usando datos de búsqueda semántica',
        urgency: previousData.relevantDocs[0]?.urgency || 'media',
        recommendedAction: `Consultar protocolo: ${previousData.relevantDocs[0]?.title || 'general'}`,
        differentialDiagnosis: previousData.relevantDocs.map(d => d.title)
      },
      source: 'parse-error-fallback',
      fallbackUsed: true,
      tokensUsed: aiData?.usage?.total_tokens || 0,
      rawContent: content
    }
  }];
}

// Normalizar campo urgency (por si la IA devuelve variaciones)
const urgencyMap = {
  'crítica': 'critica', 'critical': 'critica', 'critica': 'critica',
  'alta': 'alta', 'high': 'alta',
  'media': 'media', 'medium': 'media', 'moderada': 'media',
  'baja': 'baja', 'low': 'baja'
};

const normalizedUrgency = urgencyMap[String(parsed.urgency || '').toLowerCase()] || 'media';

return [{
  json: {
    patientHash: previousData.patientHash,
    age: previousData.age,
    symptoms: previousData.symptoms,
    vitals: previousData.vitals,
    hasCriticalVitals: previousData.hasCriticalVitals,
    relevantDocs: previousData.relevantDocs,
    aiAnalysis: {
      analysis: parsed.analysis || 'Sin análisis disponible',
      urgency: normalizedUrgency,
      recommendedAction: parsed.recommendedAction || 'Evaluación médica presencial',
      differentialDiagnosis: Array.isArray(parsed.differentialDiagnosis) ? parsed.differentialDiagnosis : []
    },
    source: 'openrouter-gemini-2.0-flash',
    fallbackUsed: false,
    tokensUsed: aiData?.usage?.total_tokens || 0
  }
}];

// ═══════════════════════════════════════
// FALLBACK: ANÁLISIS BASADO EN REGLAS
// ═══════════════════════════════════════
// Se ejecuta cuando la llamada a OpenRouter falla.
// Genera una respuesta determinista usando búsqueda semántica + vitales.

const data = $('🔍 Búsqueda Semántica').first().json;

let urgency = 'media';
let recommendedAction = 'Evaluación médica presencial';

if (data.hasCriticalVitals) {
  urgency = 'critica';
  recommendedAction = '🚨 Activar protocolo de emergencia. Derivar a guardia inmediatamente.';
} else if (data.relevantDocs[0]?.urgency === 'critica') {
  urgency = 'alta';
  recommendedAction = `Evaluación urgente. Consultar protocolo: ${data.relevantDocs[0].title}`;
} else if (data.relevantDocs[0]?.urgency === 'alta') {
  urgency = 'alta';
  recommendedAction = 'Derivar a guardia dentro de las próximas 2 horas';
} else {
  urgency = 'baja';
  recommendedAction = 'Consulta programada con médico de cabecera';
}

return [{
  json: {
    patientHash: data.patientHash,
    age: data.age,
    symptoms: data.symptoms,
    vitals: data.vitals,
    hasCriticalVitals: data.hasCriticalVitals,
    relevantDocs: data.relevantDocs,
    aiAnalysis: {
      analysis: `FALLBACK REGLAS: top match con "${data.relevantDocs[0]?.title}" (similitud ${data.relevantDocs[0]?.similarity}).`,
      urgency,
      recommendedAction,
      differentialDiagnosis: data.relevantDocs.map(d => d.title)
    },
    source: 'fallback-rules-engine',
    fallbackUsed: true,
    tokensUsed: 0
  }
}];

// ═══════════════════════════════════════
// CLASIFICACIÓN FINAL + PRIORIZACIÓN
// ═══════════════════════════════════════
// Combina la urgencia del análisis con los signos vitales
// para definir la prioridad final y el SLA.

const d = $input.first().json;

const urgencyScore = {
  critica: 4,
  alta: 3,
  media: 2,
  baja: 1
};

let aiScore = urgencyScore[d.aiAnalysis.urgency] || 2;

// Override por signos vitales críticos
if (d.hasCriticalVitals && aiScore < 3) aiScore = 3;

const priority = 
  aiScore >= 4 ? 'P1_CRITICAL' :
  aiScore === 3 ? 'P2_HIGH' :
  aiScore === 2 ? 'P3_MEDIUM' : 'P4_LOW';

const slaMinutes = 
  priority === 'P1_CRITICAL' ? 5 :
  priority === 'P2_HIGH' ? 30 :
  priority === 'P3_MEDIUM' ? 120 : 1440;

return [{
  json: {
    ...d,
    triage: {
      priority,
      urgency: d.aiAnalysis.urgency,
      slaMinutes,
      slaDeadline: new Date(Date.now() + slaMinutes * 60000).toISOString(),
      overrideApplied: d.hasCriticalVitals && urgencyScore[d.aiAnalysis.urgency] < 3
    }
  }
}];

